class Solution {
    public int getMinSwaps(String num, int k) {
        int[] digits = new int[10];
        Arrays.fill(digits, 0);
        int result = 0;

        for (int i = 0; i < num.length(); i++) {
            int digit = Character.getNumericValue(num.charAt(i));
            digits[digit]++;
        }

        int[] sortedDigits = Arrays.stream(digits).boxed().sorted().toArray();
        Arrays.sort(sortedDigits);

        int swaps = 0;
        for (int i = 0; i < k; i++) {
            int digit1 = sortedDigits[i];
            int digit2 = sortedDigits[i + 1];
            if (digit1 > digit2) {
                swaps++;
                num = num.replace(num.charAt(digit1), num.charAt(digit2));
            }
        }

        return swaps;
    }
}
